import json
import re
from collections import defaultdict

# Load data
with open(var_functions.query_db_24) as f:
    books = json.load(f)
with open(var_functions.query_db_26) as f:
    reviews = json.load(f)

print('Books', len(books), 'Reviews', len(reviews))

# Extract years
books_with_years = []
for b in books:
    m = re.findall(r'\b(19\d{2}|20[0-2]\d)\b', b['details'])
    if m:
        for match in m:
            y = int(match)
            if 1900 <= y <= 2025:
                decade = str(y // 10 * 10) + 's'
                books_with_years.append({
                    'id': b['book_id'].split('_')[1],
                    'decade': decade
                })
                break

print('Books with years', len(books_with_years))

# Map book IDs
book_map = {}
for b in books_with_years:
    book_map[b['id']] = b['decade']

# Join with reviews
joined = []
for r in reviews:
    rid = r['purchase_id'].split('_')[1]
    if rid in book_map:
        joined.append({
            'book': rid,
            'decade': book_map[rid],
            'rating': float(r['rating'])
        })

print('Joined reviews', len(joined))

# Group by decade
decades = defaultdict(lambda: {'ratings': [], 'books': set()})
for j in joined:
    decades[j['decade']]['ratings'].append(j['rating'])
    decades[j['decade']]['books'].add(j['book'])

# Calculate averages
results = []
for d, data in decades.items():
    if len(data['books']) >= 10:
        avg = sum(data['ratings']) / len(data['ratings'])
        results.append((d, avg, len(data['books']), len(data['ratings'])))

results.sort(key=lambda x: x[1], reverse=True)

print('Valid decades', len(results))
for r in results:
    print(r[0], round(r[1], 3), r[2], r[3])

if results:
    print('BEST:', results[0][0])

