import json
import os

# List all files in /tmp
print('Files in /tmp:')
for filename in os.listdir('/tmp'):
    if filename.endswith('.json'):
        filepath = os.path.join('/tmp', filename)
        size = os.path.getsize(filepath)
        print(f"  {filename} ({size} bytes)")

        # Try to load and see what's in it
        try:
            with open(filepath) as f:
                data = json.load(f)
                print(f"    Records: {len(data)}")
                if len(data) > 0:
                    print(f"    First record keys: {list(data[0].keys())}")
                    if 'details' in data[0]:
                        print(f"    Sample details: {data[0]['details'][:100]}")
                    if 'purchase_id' in data[0]:
                        print(f"    Sample purchase_id: {data[0]['purchase_id']}")
                    if 'rating' in data[0]:
                        print(f"    Sample rating: {data[0]['rating']}")
        except Exception as e:
            print(f"    Error: {e}")

# Also check what's in globals related to our queries
print('\n\nGlobal variables containing our data:')
for key in list(globals().keys()):
    if 'query_db' in key or 'list_db' in key:
        print(f"  {key}: {type(globals()[key])}")

